class ImageModel {
  String image_data;
  DateTime created_at;
  DateTime updated_at;

  static String base64512512 =
      "";

  ImageModel({
    required this.image_data,
    required this.created_at,
    required this.updated_at,
  }) {}

  factory ImageModel.create() {
    final image = ImageModel(
      image_data: base64512512,
      created_at: DateTime.now(),
      updated_at: DateTime.now(),
    );
    return image;
  }

  factory ImageModel.fromJson(Map<String, dynamic> json) {
    final project = ImageModel.create();

    project.image_data = json["image_data"];
    project.created_at = DateTime.tryParse(json["created_at"] ?? "")!;
    project.updated_at = DateTime.tryParse(json["updated_at"] ?? "")!;

    return project;
  }

  Map<String, dynamic> toJson() {
    return {
      "image_data": image_data,
      "created_at": created_at,
      "updated_at": updated_at,
    };
  }
}
